// Code interpreter: the dataset is loaded once, then the agent's JavaScript runs against it.
// The agent passes its code as the tool input (`query`); we eval it with `data` in scope
// and return whatever it prints with console.log().

// 1) Get the agent's code (the tool input)
let code = (typeof query !== 'undefined' && query) ? String(query) : '';
if (!code) {
  try { const item = $input.first().json; code = item.query || item.code || item.input || ''; } catch (e) {}
}

// 2) Load the dataset once (CSV -> array of row objects)
const CSV_URL = 'https://raw.githubusercontent.com/zero-to-mastery/file-io/main/spotify-2023.csv';
const csvText = String(await this.helpers.httpRequest({ url: CSV_URL, json: false }));

function parseCSV(text) {
  const rows = [];
  let row = [], field = '', inQ = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQ) {
      if (c === '"' && text[i + 1] === '"') { field += '"'; i++; }
      else if (c === '"') { inQ = false; }
      else { field += c; }
    } else {
      if (c === '"') { inQ = true; }
      else if (c === ',') { row.push(field); field = ''; }
      else if (c === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else if (c === '\r') { /* ignore */ }
      else { field += c; }
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const matrix = parseCSV(csvText);
const headers = matrix[0];
const data = matrix.slice(1)
  .filter(r => r.length === headers.length)
  .map(r => { const o = {}; headers.forEach((h, i) => { o[h] = r[i]; }); return o; });

// 3) Run the agent's code, capturing console.log output
const logs = [];
const console = { log: (...a) => logs.push(a.map(x => (typeof x === 'object' ? JSON.stringify(x) : String(x))).join(' ')) };

try {
  eval(code);
} catch (e) {
  return 'ERROR running your code: ' + e.message + '\nRemember: `data` is the array of song objects; print the answer with console.log().';
}

return logs.length ? logs.join('\n') : '(no output — remember to console.log() your final answer)';
